const item = $input.first().json;
const emailBody = item.snippet || '';
const subject = item.Subject || '';
const sender = item.From || '';

// Strip HTML
let cleanBody = emailBody.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

// Prompt injection protection
const injectionPatterns = [
  /ignore (all |any )?(previous |prior |above )?instructions/gi,
  /you are now/gi,
  /new instructions:/gi,
  /system prompt/gi,
  /\[INST\]/gi,
  /<\|im_start\|>/gi,
  /```(system|assistant)/gi,
  /forget (all |any )?(previous |prior )?/gi,
  /disregard/gi,
  /override/gi
];

for (const pattern of injectionPatterns) {
  cleanBody = cleanBody.replace(pattern, '[BLOCKED]');
}

cleanBody = cleanBody.substring(0, 4000);

// Extract sector from body
const bodyLower = cleanBody.toLowerCase().trim();

const sectorMap = {
  'nifty it': 'NIFTY IT', 'nifty bank': 'NIFTY BANK', 'nifty pharma': 'NIFTY PHARMA',
  'nifty auto': 'NIFTY AUTO', 'nifty fmcg': 'NIFTY FMCG', 'nifty metal': 'NIFTY METAL',
  'nifty energy': 'NIFTY ENERGY', 'nifty realty': 'NIFTY REALTY',
  'nifty financial services': 'NIFTY FIN SERVICE', 'nifty fin': 'NIFTY FIN SERVICE',
  'it sector': 'NIFTY IT', 'banking sector': 'NIFTY BANK', 'pharma sector': 'NIFTY PHARMA',
  'auto sector': 'NIFTY AUTO', 'fmcg sector': 'NIFTY FMCG', 'metal sector': 'NIFTY METAL',
  'energy sector': 'NIFTY ENERGY', 'realty sector': 'NIFTY REALTY',
  'it ': 'NIFTY IT', 'banking': 'NIFTY BANK', 'pharma': 'NIFTY PHARMA',
  'auto': 'NIFTY AUTO', 'fmcg': 'NIFTY FMCG', 'metals': 'NIFTY METAL',
  'energy': 'NIFTY ENERGY', 'real estate': 'NIFTY REALTY', 'realty': 'NIFTY REALTY',
  'financial services': 'NIFTY FIN SERVICE', 'nbfc': 'NIFTY FIN SERVICE'
};

let sector = 'NIFTY IT'; // default
for (const [key, value] of Object.entries(sectorMap)) {
  if (bodyLower.includes(key)) {
    sector = value;
    break;
  }
}

// Extract quarters if mentioned
let quarters = 4;
const quarterMatch = bodyLower.match(/(\d+)\s*quarter/i);
if (quarterMatch) quarters = Math.min(parseInt(quarterMatch[1]), 8);

return [{
  json: {
    body: cleanBody,
    subject: subject.substring(0, 200),
    from: sender.substring(0, 200),
    sector,
    quarters
  }
}];

const sanitized = $('Sanitize & Extract Sector').item.json;
const skillResponse = $('Fetch ER Skill').item.json;

let skillContent = '';
if (typeof skillResponse === 'string') {
  skillContent = skillResponse;
} else if (skillResponse.data) {
  skillContent = skillResponse.data;
} else if (skillResponse.body) {
  skillContent = skillResponse.body;
} else {
  skillContent = JSON.stringify(skillResponse);
}

return [{
  json: {
    body: sanitized.body,
    subject: sanitized.subject,
    from: sanitized.from,
    sector: sanitized.sector,
    quarters: sanitized.quarters,
    skill: skillContent
  }
}];

